#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long *a = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &a[i]);
        int cnt = 0;
        for (int i = 1; i < N - 1; ++i) {
            if ((a[i] > a[i-1] && a[i] > a[i+1]) || (a[i] < a[i-1] && a[i] < a[i+1]))
                ++cnt;
        }
        printf("%d\n", cnt);
        free(a);
    }
    return 0;
}

